        /* 导航栏 */
        nav {
            position: sticky;
            top: 0;
            z-index: 1000;
            background: rgba(10, 14, 39, 0.95);
            backdrop-filter: blur(10px);
            border-bottom: 2px solid #ff4655;
            padding: 0 20px;
            display: flex;
            align-items: center;
            justify-content: space-between;
            height: 70px;
            box-shadow: 0 4px 15px rgba(255, 70, 85, 0.2);
        }

        .logo {
            font-size: 24px;
            font-weight: bold;
            background: linear-gradient(90deg, #ff4655 0%, #ffcf40 100%);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
            text-transform: uppercase;
            letter-spacing: 2px;
        }

        .nav-menu {
            display: flex;
            list-style: none;
            gap: 30px;
        }

        .nav-menu a {
            color: #e0e0e0;
            text-decoration: none;
            font-size: 14px;
            font-weight: 500;
            text-transform: uppercase;
            letter-spacing: 1px;
            transition: all 0.3s ease;
            position: relative;
        }

        .nav-menu a:hover {
            color: #ff4655;
        }

        .nav-menu a::after {
            content: '';
            position: absolute;
            bottom: -5px;
            left: 0;
            width: 0;
            height: 2px;
            background: #ff4655;
            transition: width 0.3s ease;
        }

        .nav-menu a:hover::after {
            width: 100%;
        }

        /* 欢迎区域 */
        .hero {
            min-height: 600px;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            padding: 60px 20px;
            text-align: center;
            background: linear-gradient(180deg, rgba(255, 70, 85, 0.1) 0%, rgba(10, 14, 39, 0) 100%);
            border-bottom: 1px solid rgba(255, 70, 85, 0.3);
        }

        .hero h1 {
            font-size: clamp(32px, 8vw, 72px);
            font-weight: 900;
            margin-bottom: 20px;
            text-transform: uppercase;
            letter-spacing: 3px;
            line-height: 1.2;
            color: #fff;
        }

        .hero h1 span {
            color: #ff4655;
        }

        .hero p {
            font-size: 18px;
            color: #a0a0a0;
            margin-bottom: 40px;
            max-width: 600px;
        }

        .search-box {
            display: flex;
            gap: 10px;
            width: 100%;
            max-width: 500px;
            margin-bottom: 20px;
        }

